def edit_file(self, filename: str) -> None:
    import subprocess

    editor = self.get_editor()
    environ: dict[str, str] | None = None

    if self.env:
        environ = os.environ.copy()
        environ.update(self.env)

    popen_kwargs: dict[str, t.Any] = {}

    if self.process_priority is not None and self.process_priority != "normal":
        if WIN:
            priority_class = getattr(
                subprocess,
                _editor_priority_windows_classes[self.process_priority],
                None,
            )

            if priority_class is not None:
                popen_kwargs["creationflags"] = priority_class
        else:
            nice_value = _editor_priority_nice_values[self.process_priority]

            def _set_priority(nice_value: int = nice_value) -> None:
                try:
                    os.nice(nice_value)
                except OSError:
                    # Not permitted (e.g. raising priority without
                    # privileges) or not supported on this system.
                    pass

            popen_kwargs["preexec_fn"] = _set_priority

    try:
        c = subprocess.Popen(
            f'{editor} "{filename}"', env=environ, shell=True, **popen_kwargs
        )
        exit_code = c.wait()

